(window.webpackJsonp=window.webpackJsonp||[]).push([[357],{984:function(n,r){n.exports='\x3c!-- \r\ntitle: Nginx\r\nsort: \r\n--\x3e \r\n\r\n# Nginx入门\r\n\r\n> [OpenResty](http://openresty.org/cn/)\r\n\r\n## 配置\r\n\r\n```bash\r\nvim /etc/nginx/sites-enabled/default \r\nnginx -s reload\r\n```\r\n\r\n## 基础\r\n\r\n```nginx\r\nlocation /test {\r\n\techo "fzf";\t\t# 输出内容\r\n    proxy_pass https://baidu.com/;\t\t# 重定向\r\n}\r\n```\r\n\r\n```nginx\r\n# 负载均衡 权重\r\nupstream group1{\r\n\tserver 192.168.0.1:80 weight=2;\r\n\tserver 192.168.0.1:8080 weight=1;\r\n}\r\n\r\nserver{\r\n    location /test/{\r\n        # 随机重定向到两个网页\r\n        proxy_pass http://group1/;\r\n    }\r\n}\r\n```\r\n\r\n## 实例\r\n\r\n- 作为文件服务器使用\r\n\r\n```nginx\r\nlocation /app {\r\n    # 遍历目录\r\n    autoindex on;\r\n    # 文件大小显示\r\n    autoindex_exact_size off;\r\n    # 显示服务器时间\r\n    autoindex_localtime on;\r\n    # 中文文件夹转码\r\n    charset utf-8;\r\n}\r\n```\r\n\r\n'}}]);